SELECT *
FROM election_results
WHERE year = 1925;

SELECT p.party_name, p.party_leader
FROM parties p
JOIN congress c ON p.party_leader = c.president;

SELECT president
FROM congress
WHERE congress_number = 115;

SELECT COUNT(*) AS num_elections
FROM election_results
WHERE year = 1925;

SELECT candidate_name
FROM election_result_details
WHERE votes_received > (
    SELECT AVG(votes_received)
    FROM election_result_details
);

SELECT party_name 
FROM parties 
WHERE party_id > 5;
